1	import { describe, it, expect } from "vitest";
2	import { runScenario } from "./claim-office.js";
3	
4	describe("MHPCO Claim Office — quote (base premiums)", () => {
5	  // Edge case: simplest possible
6	  it("empty item list → premium 5 (only processing fee)", () => {
7	    const result = runScenario({
8	      customer: { yearsWithMHPCO: 0 },
9	      steps: [{ op: "quote", items: [] }],
10	    });
11	    expect(result).toEqual({ results: [{ premium: 5 }] });
12	  });
13	
14	  // Single main items — base premium + 5 fee, no other modifiers
15	  // (newcomer 0 years => +10% first insurance applies per item)
16	  it.todo("single sword (steel, ench 3): 100 base + 10 first + 5 fee → 115");
17	  it.todo("single amulet (ench 2): 60 base + 6 first + 5 fee → 71");
18	  it.todo("single staff (ench 1): 80 base + 8 first + 5 fee → 93");
19	  it.todo("single potion (ench 1): 40 base + 4 first + 5 fee → 49");
20	});
21	
22	describe("MHPCO Claim Office — quote (component blocks)", () => {
23	  it.todo("2 runes → 50 G base premium (no block)");
24	  it.todo("3 runes → 60 G base premium (block applies)");
25	  it.todo("4 runes → 100 G base premium (no block — block requires exactly 3)");
26	  it.todo("7 runes → 175 G base premium");
27	  it.todo("2 runes + 1 moonstone → 75 G base premium (no block: different types)");
28	  it.todo("3 runes + 3 moonstones → 120 G base premium (two separate blocks)");
29	});
30	
31	describe("MHPCO Claim Office — quote (item-specific modifiers)", () => {
32	  it.todo("cursed sword adds 50% surcharge on the item base premium");
33	  it.todo("sword with exactly enchantment 5 → high-enchantment surcharge applies");
34	  it.todo("sword with enchantment 4 → no high-enchantment surcharge");
35	  it.todo("cursed sword with enchantment 5 → both curse and high-enchantment surcharges apply");
36	  it.todo("each item in a quote is treated as a first insurance (+10%) regardless of customer history");
37	});
38	
39	describe("MHPCO Claim Office — quote (policy-wide modifiers)", () => {
40	  it.todo("customer with exactly 2 years → 20% loyalty discount applies");
41	  it.todo("customer with fewer than 2 years → no loyalty discount");
42	  it.todo("second quote in scenario → 15% follow-up contract discount applies");
43	  it.todo("first quote in scenario → no follow-up discount");
44	});
45	
46	describe("MHPCO Claim Office — quote (modifier scope on multi-item policies)", () => {
47	  it.todo("cursed sword (100) + plain amulet (60): base 160, curse adds 50 (on cursed item only) → 210 before fee");
48	});
49	
50	describe("MHPCO Claim Office — quote (rounding)", () => {
51	  it.todo("premium that yields 197.5 G → 198 G (rounded up, MHPCO's favor)");
52	  it.todo("intermediate amounts kept as fractions; only final premium rounded");
53	});
54	
55	describe("MHPCO Claim Office — quote (integration examples)", () => {
56	  it.todo("newcomer cursed sword (steel, ench 3, 0 years): 100 + 50 curse + 10 first + 5 fee → 165");
57	  it.todo("long-standing 2nd contract cursed sword (steel, ench 7, 3 years): 100 + 50 + 30 − 20 + 10 − 15 + 5 → 160");
58	});
59	
60	describe("MHPCO Claim Office — claim (standard reimbursement)", () => {
61	  it.todo("regular sword (steel, ench 3), damage 500 → payout 400 (full minus 100 deductible)");
62	  it.todo("rune (value 250), damage 200 → payout 100 (full minus deductible, no special clause)");
63	});
64	
65	describe("MHPCO Claim Office — claim (special clauses)", () => {
66	  it.todo("dragon-material sword, ench 5, damage 800 → payout 700 (dragon: full then deductible)");
67	  it.todo("steel sword, ench 9, damage 1000 → payout 400 (high-enchantment 50% then deductible)");
68	  it.todo("dragon-material sword, ench 8, damage 1000 → payout 400 (high-ench clause applies, then deductible)");
69	  it.todo("dragon-material sword, ench 9, damage 1000 → payout 400 (both apply, 50% rule wins)");
70	});
71	
72	describe("MHPCO Claim Office — claim (deductible per damage event)", () => {
73	  it.todo("dragon attack damages sword (500) and amulet (300) → payout 600 (deductible per item)");
74	});
75	
76	describe("MHPCO Claim Office — claim (cap)", () => {
77	  it.todo("sword + amulet → insurance sum 1600, cap 3200");
78	  it.todo("cursed sword → cap 2000 (based on unmodified insurance value)");
79	  it.todo("sword + 3 runes → insurance sum 1750 (block discount does not affect insurance sum)");
80	  it.todo("two swords → insurance sum 2000, cap 4000");
81	  it.todo("sword (cap 2000), two claims of 1500: first payout 1400 remaining 600; second payout 600 remaining 0");
