94	  it.todo("quote with unknown item type → throws / non-zero exit");
95	  it.todo("claim referencing an item not in the policy → throws / non-zero exit");
96	  it.todo("claim referencing an unknown item type → throws / non-zero exit");
97	  it.todo("claim with a negative damage amount → throws / non-zero exit");
98	});
